// Bemenő adatok feldolgozása a webhook-ból
// Többféle hozzáférési mód (n8n verziófüggő)
let input = {};
try { input = $input.item.json; } catch(e) {}
try { if (!input || !input.businessName) input = $json; } catch(e) {}

const projectType = input.projectType || 'landing_page';
const businessName = input.businessName || 'My Business';
const language = input.language || 'hu';
const description = input.description || '';
const designStyle = input.designStyle || 'modern';
const primaryColor = input.primaryColor || '#6366f1';
const secondaryColor = input.secondaryColor || '#8b5cf6';
const hero = input.hero || { enabled: true, height: 600 };
const logo = input.logo || null;

// Oldalak: lehet string tömb (régi formátum) vagy objektum tömb (új formátum)
let pages = input.pages || [];
if (pages.length > 0 && typeof pages[0] === 'string') {
  pages = pages.map(p => ({ name: p, slug: p.toLowerCase(), description: '', subpages: [] }));
}
if (pages.length === 0) {
  pages = [
    { name: 'Kezdőlap', slug: 'home', description: '', subpages: [] },
    { name: 'Rólunk', slug: 'about', description: '', subpages: [] },
    { name: 'Kapcsolat', slug: 'contact', description: '', subpages: [] }
  ];
}

return {
  businessName,
  projectType,
  language,
  description,
  designStyle,
  primaryColor,
  secondaryColor,
  hero,
  logo,
  pages
};

const data = $input.all()[0].json;

// Oldalak szöveges felsorolása
const pageList = data.pages.map(p => {
  let line = p.name + ' (' + p.slug + ')';
  if (p.description) line += ': ' + p.description;
  if (p.subpages && p.subpages.length > 0) {
    line += ' [Aloldalak: ' + p.subpages.map(sp => sp.name + '(' + sp.slug + ')' + (sp.description ? ': ' + sp.description : '')).join(', ') + ']';
  }
  return line;
}).join('\n');

const heroInfo = data.hero && data.hero.enabled 
  ? `Hero section: YES, height: ${data.hero.height}px. Generate a compelling hero with title, subtitle, CTA button.`
  : 'Hero section: NO. Do not include a hero section.';

const prompt = `You are a Gravity CMS expert. Generate a complete Gravity CMS website structure.

Project: ${data.businessName}
Type: ${data.projectType}
Language: ${data.language}
Description: ${data.description}
Design: ${data.designStyle}
Primary color: ${data.primaryColor}
Secondary color: ${data.secondaryColor}
${heroInfo}

Pages to generate with custom descriptions:
${pageList}

Output MUST be valid JSON:
{
  "pages": {
    "[slug]": {
      "template": "default",
      "route": "/[slug]",
      "title": "page title in ${data.language}",
      "content": {
        "hero": { "title": "...", "subtitle": "...", "cta_text": "...", "cta_link": "/contact" },
        "sections": [{ "type": "features|testimonials|pricing|gallery|text|custom", "title": "...", "content": "..." }]
      },
      "meta": { "title": "SEO title", "description": "SEO description" },
      "subpages": { "[subslug]": { ... } }
    }
  },
  "config": {
    "system": { "site_name": "${data.businessName}", "language": "${data.language}" },
    "theme": { "name": "${data.designStyle}", "primary_color": "${data.primaryColor}", "secondary_color": "${data.secondaryColor}" },
    "plugins": ["recommended-gravity-plugins"]
  },
  "admin_structure": { "blueprints": {}, "forms": [] }
}

Use the provided page descriptions to generate relevant content. Make content professional, SEO-optimized.`;

return { prompt };

const fs = require('fs');
const path = require('path');

const response = $input.all()[0].json;

let content;
try {
  const aiResponse = response.choices[0].message.content;
  let jsonStr = aiResponse;
  if (jsonStr.includes('```json')) jsonStr = jsonStr.split('```json')[1].split('```')[0].trim();
  else if (jsonStr.includes('```')) jsonStr = jsonStr.split('```')[1].split('```')[0].trim();
  content = JSON.parse(jsonStr);
} catch (e) {
  content = { error: "Failed to parse AI response", raw: response.choices[0].message.content };
}

// Fájlba mentés
const outputDir = '/home/node/output';
const bizName = ($items('Bemenet feldolgozása (Code)').$node['Bemenet feldolgozása (Code)'].json || {}).businessName || 'unknown';
const safeName = bizName.toLowerCase().replace(/[^a-z0-9]/g, '_').substring(0, 30);
const ts = new Date().toISOString().replace(/[:.]/g, '-');
const filename = path.join(outputDir, safeName + '_' + ts + '.json');

try {
  if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true });
  fs.writeFileSync(filename, JSON.stringify(content, null, 2), 'utf8');
} catch (err) {}

return { generated: content, saved_to: filename, timestamp: new Date().toISOString(), model: response.model || 'deepseek-chat', usage: response.usage || {} };
